// Push-notification service worker. Named `firebase-messaging-sw.js`
// for historical reasons — the Firebase JS SDK's `getToken()` call in
// the app looks for this exact path when binding the push subscription.
// The SW itself no longer imports the Firebase compat SDK: we handle
// push events directly via the standard Web Push `push` event, which
// is platform-standard and works reliably on iOS Safari PWAs (the
// SDK's `onBackgroundMessage` filter dropped data-only messages in
// some contexts).
//
// Templated — the live file at /firebase-messaging-sw.js is
// generated by scripts/generate-sw.mjs from VITE_FIREBASE_*
// environment variables (see .env.example). Run `pnpm dev` or
// `pnpm build` to regenerate; the script also runs in CI.
//
// This SW also serves as the PWA install signal. Modern Chrome (99+)
// no longer requires a fetch handler; adding a no-op one triggers a
// console warning about navigation overhead.

/** Raw push-event handler. Fires for every push regardless of source
 *  (FCM, DevTools Push, direct Web Push). Always calls
 *  `showNotification()` inside the event's waitUntil — iOS Safari
 *  silently drops pushes that don't surface a notification from the
 *  push event.
 *
 *  Payload shape (from functions/src/fcm.ts → sendDisplayPush):
 *    { data: { title, body, kind, wardId, ...routing fields } }
 *  The top-level `notification` field is intentionally absent — that
 *  would trigger the browser's auto-display path in some contexts and
 *  bypass our custom handler. */
self.addEventListener("push", (event) => {
  const payload = readPayload(event.data);
  const data = payload.data ?? payload ?? {};
  const title = data.title ?? "Steward";
  const body = data.body ?? "";
  event.waitUntil(
    self.registration.showNotification(title, {
      body,
      icon: "/icon.svg",
      badge: "/icon.svg",
      data,
    }),
  );
});

function readPayload(pushData) {
  if (!pushData) return {};
  try {
    return pushData.json();
  } catch {
    try {
      return { body: pushData.text() };
    } catch {
      return {};
    }
  }
}

/** Deep-link a notification tap into the matching in-app surface.
 *  Keep the `data.kind` map here in sync with the FCM payloads in
 *  functions/src/ (invitationResponseNotify, invitationReplyNotify,
 *  onCommentCreate). If an existing tab is already on our origin we
 *  focus + navigate that one; otherwise we open a new window. */
self.addEventListener("notificationclick", (event) => {
  event.notification.close();
  const url = routeForPushData(event.notification.data);
  if (!url) return;
  event.waitUntil(focusOrOpen(url));
});

function routeForPushData(data) {
  if (!data || typeof data !== "object") return "/";
  switch (data.kind) {
    case "invitation-response":
    case "invitation-reply":
      return data.invitationId
        ? `/schedule?chat=${encodeURIComponent(data.invitationId)}`
        : "/schedule";
    case "mention":
      return data.date ? `/week/${encodeURIComponent(data.date)}` : "/schedule";
    case "planning-open":
      return data.date ? `/week/${encodeURIComponent(data.date)}` : "/schedule";
    default:
      return "/";
  }
}

async function focusOrOpen(url) {
  const target = new URL(url, self.location.origin).href;
  const clients = await self.clients.matchAll({ type: "window", includeUncontrolled: true });
  for (const client of clients) {
    if (!client.url.startsWith(self.location.origin)) continue;
    if ("navigate" in client) {
      try {
        await client.navigate(target);
      } catch {
        // Some browsers reject cross-origin navigate; fall through to focus-only.
      }
    }
    return client.focus();
  }
  return self.clients.openWindow(target);
}
